import "@radix-ui/themes/styles.css";
import { Theme, ThemePanel, Box, Container, Button, Flex, Text, Section, Heading} from "@radix-ui/themes";
import './App.css';
import { useEffect, useState } from "react";
import { useMouseMove, useValue, animate } from "react-ui-animate";


function App() {
  const CURSOR_SIZE = 40;
  const windowWidth = window.innerWidth;
  const windowHeight = window.innerHeight;

  const x = useValue(0);
  const y = useValue(0);

  useMouseMove(({ mouseX, mouseY }) => {
    x.value = mouseX;
    y.value = mouseY;

    //get the percentage of the mouse position
    let xPercent = x.value.value / windowWidth;
    let yPercent = y.value.value / windowHeight;

    xPercent*=100;

    console.log(xPercent.toFixed(0));
  });


  return (
    <Theme style={{background: "radial-gradient(circle at 0% 0%, #0a0f39aa 0%, #00000094 80%)"}} id="theme_element" scaling="90%" grayColor="mauve" accentColor="indigo" panelBackground="translucent" appearance="dark">
      <ThemePanel />
      <Container size="4" className = "background-gradient">
        <Section>
          <Flex gap="4" direction="column">
            <Heading mt="5" size="9">Ted Fawke</Heading>
            <Heading weight="medium" size="6">Full Stack Web Developer</Heading>
            <Heading className="my_promise" weight="light" size="4">I create custom, scalable software to help companies thrive on the web.</Heading>
          </Flex>
          <Flex gap="4" direction="column">
            {/* <Button size="3" variant="outline">Get in touch</Button>
            <Button size="3" variant="soft">View my work</Button> */}
          </Flex>
        </Section>
      </Container>
    </Theme>
  );
}

export default App;
